import "fmt"

// Service1 handles domain logic for area 1.
type Service1 struct {
	ID   int
	Name string
	Data []byte
}

// Process1 executes the core processing for Service1.
func Process1(id int, name string) (*Service1, error) {
	if name == "" {
		return nil, fmt.Errorf("service1: name required")
	}
	return &Service1{ID: id, Name: name}, nil
}

